import{_ as e,o as a,c as i,ao as l}from"./chunks/framework.hY-gA2uj.js";const c=JSON.parse('{"title":"Supported pair-copula families","description":"","frontmatter":{},"headers":[],"relativePath":"paircopulas/supported_families.md","filePath":"paircopulas/supported_families.md","lastUpdated":null}'),d={name:"paircopulas/supported_families.md"};function r(s,t,o,n,p,g){return a(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="Supported-pair-copula-families" tabindex="-1">Supported pair-copula families <a class="header-anchor" href="#Supported-pair-copula-families" aria-label="Permalink to &quot;Supported pair-copula families {#Supported-pair-copula-families}&quot;">​</a></h1><p><code>VineCopulas.jl</code> uses bivariate copulas from <code>Copulas.jl</code>. A family is considered supported as a vine pair-copula when the following pieces are available and tested:</p><ol><li><p>bivariate density/log-density,</p></li><li><p><code>hfunc1</code> and <code>hfunc2</code>,</p></li><li><p><code>hinv1</code> and <code>hinv2</code> for simulation and inverse Rosenblatt transforms,</p></li><li><p>tests in the vine interface.</p></li></ol><h2 id="Current-support-table" tabindex="-1">Current support table <a class="header-anchor" href="#Current-support-table" aria-label="Permalink to &quot;Current support table {#Current-support-table}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Group</th><th style="text-align:right;">Family examples</th><th style="text-align:right;"><code>Copulas.jl</code> family exists</th><th style="text-align:right;">Vine pair-copula status</th></tr></thead><tbody><tr><td style="text-align:right;">Elliptical</td><td style="text-align:right;">Gaussian, Student-t</td><td style="text-align:right;">Yes</td><td style="text-align:right;">Tested</td></tr><tr><td style="text-align:right;">Archimedean</td><td style="text-align:right;">Clayton, Frank, Gumbel, AMH, Joe</td><td style="text-align:right;">Yes</td><td style="text-align:right;">Tested</td></tr><tr><td style="text-align:right;">Additional Archimedean</td><td style="text-align:right;">Gumbel–Barnett, Inverse Gaussian</td><td style="text-align:right;">Yes</td><td style="text-align:right;">Tested</td></tr><tr><td style="text-align:right;">BB families</td><td style="text-align:right;">BB1, BB2, BB3, BB6, BB7, BB8, BB9, BB10</td><td style="text-align:right;">Yes</td><td style="text-align:right;">Tested</td></tr><tr><td style="text-align:right;">Extreme-value</td><td style="text-align:right;">Logistic, Galambos, Hüsler–Reiss, Mixed, asymmetric tails, Marshall–Olkin, Cuadras–Augé, BC2, extreme-t</td><td style="text-align:right;">Yes</td><td style="text-align:right;">Tested</td></tr><tr><td style="text-align:right;">Survival/rotated</td><td style="text-align:right;"><code>SurvivalCopula</code> wrappers</td><td style="text-align:right;">Yes</td><td style="text-align:right;">Tested through flip rules</td></tr><tr><td style="text-align:right;">Independence</td><td style="text-align:right;"><code>IndependentCopula</code></td><td style="text-align:right;">Yes</td><td style="text-align:right;">Usually not needed explicitly in truncated trees</td></tr><tr><td style="text-align:right;">Plackett</td><td style="text-align:right;"><code>PlackettCopula</code></td><td style="text-align:right;">Yes</td><td style="text-align:right;">Not yet advertised as tested vine pair-copula</td></tr><tr><td style="text-align:right;">FGM</td><td style="text-align:right;"><code>FGMCopula</code></td><td style="text-align:right;">Yes</td><td style="text-align:right;">Not yet advertised as tested vine pair-copula</td></tr><tr><td style="text-align:right;">Raftery</td><td style="text-align:right;"><code>RafteryCopula</code></td><td style="text-align:right;">Yes</td><td style="text-align:right;">Not yet advertised as tested vine pair-copula</td></tr><tr><td style="text-align:right;">M copula</td><td style="text-align:right;"><code>MCopula</code></td><td style="text-align:right;">Yes</td><td style="text-align:right;">Not yet advertised as tested vine pair-copula</td></tr><tr><td style="text-align:right;">W copula</td><td style="text-align:right;"><code>WCopula</code></td><td style="text-align:right;">Yes</td><td style="text-align:right;">Not yet advertised as tested vine pair-copula</td></tr><tr><td style="text-align:right;">Empirical/Bernstein/Beta/Checkerboard</td><td style="text-align:right;">Several nonparametric objects</td><td style="text-align:right;">Yes</td><td style="text-align:right;">Not part of stable v0.1 vine interface</td></tr><tr><td style="text-align:right;">Subset copulas</td><td style="text-align:right;"><code>subsetdims</code> from <code>Copulas.jl</code></td><td style="text-align:right;">Yes</td><td style="text-align:right;">Useful in <code>Copulas.jl</code>; not a pair-family target here</td></tr></tbody></table><p><code>Copulas.jl</code> exports many copula families and utilities, including <code>SklarDist</code>, <code>pseudos</code>, <code>condition</code>, <code>subsetdims</code>, Plackett, FGM, Raftery, M and W copulas, and many extreme-value families. <code>VineCopulas.jl</code> does not automatically guarantee that every <code>Copulas.jl</code> bivariate family has a stable inverse conditional path in vine algorithms.</p><h2 id="Why-the-table-is-conservative" tabindex="-1">Why the table is conservative <a class="header-anchor" href="#Why-the-table-is-conservative" aria-label="Permalink to &quot;Why the table is conservative {#Why-the-table-is-conservative}&quot;">​</a></h2><p>It is not enough for a bivariate copula to have a density. Vine simulation requires inverse conditional distributions. A family should only be documented as fully supported after it passes pair-copula conditional tests and vine-level density/simulation tests.</p><h2 id="Survival-and-rotations" tabindex="-1">Survival and rotations <a class="header-anchor" href="#Survival-and-rotations" aria-label="Permalink to &quot;Survival and rotations {#Survival-and-rotations}&quot;">​</a></h2><p>Rotations are handled through <code>Copulas.SurvivalCopula</code> when the underlying base family has valid h-functions and inverse h-functions. The flip logic is implemented at the conditional level.</p>',10)])])}const u=e(d,[["render",r]]);export{c as __pageData,u as default};
